<?php

declare(strict_types=1);

// Load .env from the document root (one level up from /api/)
function contact_load_env(): array
{
    $candidates = [
        dirname(__DIR__) . '/.env',
        dirname(__DIR__, 2) . '/.env',
    ];

    $env = [];
    foreach ($candidates as $path) {
        if (!is_file($path)) {
            continue;
        }

        $lines = file($path, FILE_IGNORE_NEW_LINES | FILE_SKIP_EMPTY_LINES);
        if ($lines === false) {
            continue;
        }

        foreach ($lines as $line) {
            $line = trim($line);
            if ($line === '' || str_starts_with($line, '#')) {
                continue;
            }

            $pos = strpos($line, '=');
            if ($pos === false) {
                continue;
            }

            $key = trim(substr($line, 0, $pos));
            $value = trim(substr($line, $pos + 1));

            if (
                (str_starts_with($value, '"') && str_ends_with($value, '"')) ||
                (str_starts_with($value, "'") && str_ends_with($value, "'"))
            ) {
                $value = substr($value, 1, -1);
            }

            if ($key !== '') {
                $env[$key] = $value;
            }
        }

        break; // use first found
    }

    return $env;
}

function contact_env(array $env, array $keys, string $default = ''): string
{
    foreach ($keys as $key) {
        if (isset($env[$key]) && $env[$key] !== '') {
            return $env[$key];
        }
    }

    return $default;
}

function contact_smtp_read($socket): string
{
    $response = '';

    while (($line = fgets($socket, 515)) !== false) {
        $response .= $line;
        if (strlen($line) >= 4 && $line[3] === ' ') {
            break;
        }
    }

    if ($response === '') {
        throw new RuntimeException('SMTP server closed the connection unexpectedly.');
    }

    return $response;
}

function contact_smtp_expect($socket, array $allowedCodes): string
{
    $response = contact_smtp_read($socket);
    $code = (int) substr($response, 0, 3);

    if (!in_array($code, $allowedCodes, true)) {
        throw new RuntimeException('SMTP error: ' . trim($response));
    }

    return $response;
}

function contact_smtp_command($socket, string $command, array $allowedCodes): string
{
    fwrite($socket, $command . "\r\n");
    return contact_smtp_expect($socket, $allowedCodes);
}

function contact_smtp_escape(string $body): string
{
    $body = str_replace(["\r\n", "\r"], "\n", $body);
    $body = str_replace("\n.", "\n..", $body);
    return str_replace("\n", "\r\n", $body);
}

// --- Response helpers ---

function contact_json(int $status, array $payload): never
{
    http_response_code($status);
    echo json_encode($payload, JSON_UNESCAPED_UNICODE);
    exit;
}

// --- CORS headers ---

header('Access-Control-Allow-Origin: *');
header('Access-Control-Allow-Methods: POST, OPTIONS');
header('Access-Control-Allow-Headers: Content-Type, Authorization');
header('Content-Type: application/json; charset=utf-8');

if (($_SERVER['REQUEST_METHOD'] ?? '') === 'OPTIONS') {
    http_response_code(200);
    exit;
}

if (($_SERVER['REQUEST_METHOD'] ?? '') !== 'POST') {
    contact_json(405, ['success' => false, 'error' => 'Method not allowed']);
}

// --- Parse body ---

$raw = file_get_contents('php://input');
$body = is_string($raw) ? json_decode($raw, true) : null;

if (!is_array($body)) {
    contact_json(400, ['success' => false, 'error' => 'Invalid JSON body']);
}

$name    = trim((string) ($body['name']    ?? ''));
$email   = trim((string) ($body['email']   ?? ''));
$company = trim((string) ($body['company'] ?? ''));
$message = trim((string) ($body['message'] ?? ''));
$captchaToken = trim((string) ($body['captchaToken'] ?? ''));

// --- Validate required fields ---

if ($name === '' || $email === '' || $message === '') {
    contact_json(400, ['success' => false, 'error' => 'Name, email, and message are required']);
}

if (filter_var($email, FILTER_VALIDATE_EMAIL) === false) {
    contact_json(400, ['success' => false, 'error' => 'Invalid email address']);
}

// --- Verify basic math captcha (token format: "num1:num2:answer") ---

if ($captchaToken === '') {
    contact_json(400, ['success' => false, 'error' => 'Captcha token is required']);
}

$parts = explode(':', $captchaToken);

if (count($parts) !== 3) {
    contact_json(400, ['success' => false, 'error' => 'Invalid captcha token format']);
}

$num1   = (int) $parts[0];
$num2   = (int) $parts[1];
$answer = (int) $parts[2];

// Numbers generated by Math.floor(Math.random()*8)+2, so range 2-9
if ($num1 < 2 || $num1 > 9 || $num2 < 2 || $num2 > 9 || $answer !== ($num1 + $num2)) {
    contact_json(400, ['success' => false, 'error' => 'Captcha verification failed']);
}

// --- Load SMTP credentials ---

$env      = contact_load_env();
$smtpHost = contact_env($env, ['SMTP_HOST', 'Outgoing Server'], 'mail.abitcons.com');
$smtpPort = (int) contact_env($env, ['SMTP_PORT', 'SMTP Port'], '465');
$smtpUser = contact_env($env, ['SMTP_USERNAME', 'EMAIL_USER', 'emailaddress']);
$smtpPass = contact_env($env, ['SMTP_PASSWORD', 'EMAIL_PASS', 'password']);
$fromEmail = contact_env($env, ['SMTP_FROM_EMAIL', 'emailaddress'], $smtpUser);
$fromName  = contact_env($env, ['SMTP_FROM_NAME'], 'Digrro Website');

if ($smtpUser === '' || $smtpPass === '') {
    error_log('Contact form: SMTP credentials not configured');
    contact_json(500, ['success' => false, 'error' => 'Email service is not configured']);
}

// --- Build email content ---

$toEmail = 'info@digrro.com';
$subject = $company !== '' ? "Enquiry from {$company}" : "Enquiry from {$name}";

$lines = [
    "Name:    {$name}",
    "Email:   {$email}",
];

if ($company !== '') {
    $lines[] = "Company: {$company}";
}

$lines[] = '';
$lines[] = $message;

$bodyText = implode("\n", $lines);

// --- Send via SMTP ---

try {
    $transport = ($smtpPort === 465 ? 'ssl://' : '') . $smtpHost . ':' . $smtpPort;
    $socket = @stream_socket_client($transport, $errNo, $errMsg, 30, STREAM_CLIENT_CONNECT);

    if (!is_resource($socket)) {
        throw new RuntimeException('Could not connect to SMTP server: ' . $errMsg);
    }

    stream_set_timeout($socket, 30);

    contact_smtp_expect($socket, [220]);
    contact_smtp_command($socket, 'EHLO digrro.com', [250]);

    if ($smtpPort !== 465) {
        contact_smtp_command($socket, 'STARTTLS', [220]);

        if (!stream_socket_enable_crypto($socket, true, STREAM_CRYPTO_METHOD_TLS_CLIENT)) {
            throw new RuntimeException('Could not start TLS for SMTP connection.');
        }

        contact_smtp_command($socket, 'EHLO digrro.com', [250]);
    }

    contact_smtp_command($socket, 'AUTH LOGIN', [334]);
    contact_smtp_command($socket, base64_encode($smtpUser), [334]);
    contact_smtp_command($socket, base64_encode($smtpPass), [235]);
    contact_smtp_command($socket, "MAIL FROM:<{$fromEmail}>", [250]);
    contact_smtp_command($socket, "RCPT TO:<{$toEmail}>", [250, 251]);
    contact_smtp_command($socket, 'DATA', [354]);

    $headers = [
        'Date: ' . date(DATE_RFC2822),
        "From: {$fromName} <{$fromEmail}>",
        "To: Digrro <{$toEmail}>",
        "Reply-To: {$name} <{$email}>",
        "Subject: {$subject}",
        'MIME-Version: 1.0',
        'Content-Type: text/plain; charset=UTF-8',
        'Content-Transfer-Encoding: 8bit',
    ];

    fwrite($socket, implode("\r\n", $headers) . "\r\n\r\n" . contact_smtp_escape($bodyText) . "\r\n.\r\n");
    contact_smtp_expect($socket, [250]);
    contact_smtp_command($socket, 'QUIT', [221]);
    fclose($socket);

    contact_json(200, ['success' => true, 'message' => 'Your message has been sent successfully']);
} catch (Throwable $e) {
    error_log('Contact form SMTP error: ' . $e->getMessage());
    contact_json(500, ['success' => false, 'error' => 'Failed to send message. Please try again.']);
}
